// n8n Code node (no URLSearchParams)

function slugify(value) {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/[ä]/g, "ae")
    .replace(/[ö]/g, "oe")
    .replace(/[ü]/g, "ue")
    .replace(/[ß]/g, "ss")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

function mapExperienceToCode(years) {
  if (years == null) return null;
  if (years < 2) return "90001";
  return "90002"; // matches your example
}

function buildKeywords(applicant) {
  const parts = [];

  if (applicant.role) parts.push(applicant.role);
  if (Array.isArray(applicant.stack)) parts.push(...applicant.stack);

  const unique = [...new Set(parts.map(v => String(v).trim()).filter(Boolean))];

  // Keep query concise
  return unique.slice(0, 5).join(" ");
}

function encode(value) {
  return encodeURIComponent(value);
}

const input = $input.first().json;
const applicant = input.applicant || {};

const keywords = buildKeywords(applicant);
const location = applicant.location || "Stuttgart";
const experienceCode = mapExperienceToCode(applicant.experience_years);

const keywordSlug = slugify(keywords);
const locationSlug = slugify(location);

// Base URL
let url = "https://www.stepstone.de/jobs/" + keywordSlug + "/in-" + locationSlug;

// Build query string manually
let queryParts = [];

queryParts.push("whereType=autosuggest");
queryParts.push("radius=30");
queryParts.push("searchOrigin=Resultlist_top-search");

if (experienceCode) {
  queryParts.push("action=" + encode("facet_selected;experiences;" + experienceCode));
  queryParts.push("ex=" + experienceCode);
}

// Join query
const queryString = queryParts.join("&");
const finalUrl = url + "?" + queryString;

return [
  {
    json: {
      stepstone_query_url: finalUrl,
      stepstone_keywords: keywords,
      stepstone_location: location,
      filters: {
        experience_code: experienceCode,
        salary_minimum_eur: applicant.salary_minimum_eur || null,
        max_listing_age_days: applicant.max_listing_age_days || null
      }
    }
  }
];

// n8n Code node for Xing search URL
// No URLSearchParams used

function encode(value) {
  return encodeURIComponent(String(value || ""));
}

function mapCareerLevel(years) {
  // Based on your example:
  // careerLevel=3.2ebf16 appears to represent a more experienced profile
  if (years == null) return null;
  if (years < 2) return "1";
  if (years < 5) return "2";
  return "3.2ebf16";
}

function mapSincePeriod(days) {
  if (days == null) return null;
  if (days <= 1) return "LAST_DAY";
  if (days <= 7) return "LAST_WEEK";
  if (days <= 30) return "LAST_MONTH";
  return null;
}

function buildKeywords(applicant) {
  const parts = [];

  if (applicant.role) parts.push(applicant.role);
  if (Array.isArray(applicant.stack) && applicant.stack.length) {
    // For Xing, keep keywords tighter than Stepstone
    // Usually better to focus on the strongest signal
    parts.unshift(applicant.stack[0]);
  }

  const unique = [...new Set(parts.map(v => String(v).trim()).filter(Boolean))];

  // Prefer just the strongest search phrase
  // Example target: "unreal engine"
  return applicant.stack && applicant.stack.length
    ? applicant.stack[0]
    : unique.slice(0, 2).join(" ");
}

const input = $input.first().json;
