if (sincePeriod) {
  queryParts.push("sincePeriod=" + encode(sincePeriod));
}

queryParts.push("salary=" + encode(salary));

if (careerLevel) {
  queryParts.push("careerLevel=" + encode(careerLevel));
}

const finalUrl = "https://www.xing.com/jobs/search/ki?" + queryParts.join("&");

